The evolution engine watches session outcomes over time and detects three pattern types: tool ordering correlations, repeated failures, and project-specific tool usage. Each pattern, once it crosses observation and success-rate thresholds, generates a rule in the FTAI DSL.

```rust
use anyhow::Result;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum RuleSource {
    OrderingPattern,
    RepeatedFailure,
    ProjectPattern,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GeneratedRule {
    pub name: String,
    pub source: RuleSource,
    pub confidence: f64,
    pub ftai_rule: String,
}

const MIN_OBSERVATIONS: usize = 5;
const MIN_SUCCESS_RATE: f64 = 0.8;
const MAX_ACTIVE_RULES: usize = 20;

pub struct EvolutionEngine {
    store: EvolutionStore,
    min_sessions: usize,
}

impl EvolutionEngine {
    pub fn new(store: EvolutionStore) -> Self {
        Self { store, min_sessions: 3 }
    }

    pub fn analyze_and_evolve(&self, outcome: &SessionOutcome) -> Result<Vec<GeneratedRule>> {
        self.store.save_outcome(outcome)?;

        // Auto-disable ineffective rules
        for name in &self.store.check_auto_disable()? {
            self.store.disable_rule(name)?;
        }

        let count = self.store.session_count()?;
        if count < self.min_sessions { return Ok(vec![]); }

        let active_count = self.store.active_rules()?.len();
        if active_count >= MAX_ACTIVE_RULES { return Ok(vec![]); }

        let sessions = self.store.recent_sessions(50)?;
        let budget = MAX_ACTIVE_RULES.saturating_sub(active_count);
        let mut generated = Vec::new();

        generated.extend(self.detect_ordering_patterns(&sessions));
        generated.extend(self.detect_repeated_failures(&sessions));
        generated.extend(self.detect_project_patterns(&outcome.project, &sessions));
        generated.truncate(budget);

        for rule in &generated {
            self.store.save_generated_rule(rule)?;
        }
        Ok(generated)
    }

    fn detect_ordering_patterns(&self, sessions: &[SessionOutcome]) -> Vec<GeneratedRule> {
        let mut pair_stats: HashMap<(String, String), (usize, usize)> = HashMap::new();
        for session in sessions {
            let is_success = session.success.is_success();
            for window in session.tool_calls.windows(2) {
                let (a, b) = (&window[0].tool_name, &window[1].tool_name);
                if a == b { continue; }
                let entry = pair_stats.entry((a.clone(), b.clone())).or_insert((0, 0));
                entry.1 += 1;
                if is_success { entry.0 += 1; }
            }
        }

        pair_stats.iter()
            .filter(|(_, (_, total))| *total >= MIN_OBSERVATIONS)
            .filter(|(_, (succ, total))| (*succ as f64 / *total as f64) >= MIN_SUCCESS_RATE)
            .map(|((a, b), (succ, total))| {
                let rate = *succ as f64 / *total as f64;
                let name = format!("evo-order-{a}-before-{b}");
                let ftai_rule = format!(
                    "rule {name} {{\n  scope \"*\"\n  on tool_call\n  when sequence(\"{a}\", \"{b}\")\n}}"
                );
                GeneratedRule { name, source: RuleSource::OrderingPattern, confidence: rate, ftai_rule }
            })
            .collect()
    }
}
```

Key design decisions: (1) MAX_ACTIVE_RULES caps at 20 to prevent rule bloat from overwhelming the system prompt. (2) MIN_OBSERVATIONS of 5 prevents premature pattern codification from insufficient data. (3) The budget system ensures new rules only fill remaining capacity. (4) Auto-disable runs before generation so ineffective rules free up slots.

The failure detector aggregates error patterns per tool, normalizing messages to the first 80 characters as a grouping key. When the same error pattern hits 5+ occurrences AND represents 30%+ of that tool's total calls, it generates a `reject` rule.

```rust
fn detect_repeated_failures(&self, sessions: &[SessionOutcome]) -> Vec<GeneratedRule> {
    let mut failure_counts: HashMap<String, HashMap<String, usize>> = HashMap::new();
    let mut total_calls: HashMap<String, usize> = HashMap::new();

    for session in sessions {
        for tc in &session.tool_calls {
            *total_calls.entry(tc.tool_name.clone()).or_default() += 1;
            if let ToolResultType::Error(ref msg) = tc.result_type {
                let key = if msg.len() > 80 { msg[..80].to_string() } else { msg.clone() };
                *failure_counts
                    .entry(tc.tool_name.clone()).or_default()
                    .entry(key).or_default() += 1;
            }
        }
    }

    let mut rules = Vec::new();
    for (tool, errors) in &failure_counts {
        let tool_total = total_calls.get(tool).copied().unwrap_or(0);
        for (error_pattern, count) in errors {
            if *count < MIN_OBSERVATIONS { continue; }
            let failure_rate = *count as f64 / tool_total as f64;
            if failure_rate < 0.3 { continue; }

            let safe_tool = sanitize_for_dsl(tool);
            let name = format!("evo-fail-{safe_tool}-{}", sha_short(error_pattern));
            let escaped = escape_for_dsl_comment(error_pattern);
            let ftai_rule = format!(
                "rule {name} {{\n  scope \"*\"\n  on tool_call\n  when tool(\"{safe_tool}\") && error_like(\"{escaped}\")\n  reject \"Repeated failure pattern\"\n}}"
            );
            rules.push(GeneratedRule {
                name, source: RuleSource::RepeatedFailure,
                confidence: failure_rate.min(0.95), ftai_rule,
            });
        }
    }
    rules
}
```

The security-critical piece is the sanitization functions:

```rust
// OWASP A03:2021 Injection prevention
fn sanitize_for_dsl(input: &str) -> String {
    input.chars().filter(|c| c.is_ascii_alphanumeric() || *c == '_' || *c == '-').collect()
}

fn escape_for_dsl_comment(input: &str) -> String {
    let mut s = input.replace('\\', "\\\\"); // Backslashes FIRST
    s = s.replace('"', "\\\"");
    s = s.replace('\n', " ");
    s = s.replace('{', " ");
    s = s.replace('}', " ");
    if s.len() > 200 { s.truncate(200); }
    s
}
```

Without sanitization, a malicious tool name like `bash"; inject(` would produce valid-looking DSL that executes arbitrary rules. The escape function handles backslashes FIRST to prevent double-escaping bypass, strips braces to prevent DSL block injection, and truncates to 200 chars to prevent payload stuffing.

This test creates sessions with mixed outcomes for the same tool ordering, ensuring the success rate (43%) stays below the 80% threshold:

```rust
#[test]
fn test_low_success_rate_no_rules() {
    let store = make_store();
    let engine = EvolutionEngine::with_min_sessions(store, 1);

    // 3 successes + 4 failures with same ordering = ~43% success rate
    for i in 0..3 {
        let outcome = make_outcome(
            &format!("ok-{i}"), "proj", OutcomeType::Success,
            vec![
                ("glob", ToolResultType::Success),
                ("file_write", ToolResultType::Success),
            ],
        );
        engine.analyze_and_evolve(&outcome).unwrap();
    }
    for i in 0..4 {
        let outcome = make_outcome(
            &format!("fail-{i}"), "proj", OutcomeType::Failure("err".into()),
            vec![
                ("glob", ToolResultType::Success),
                ("file_write", ToolResultType::Error("disk full".into())),
            ],
        );
        engine.analyze_and_evolve(&outcome).unwrap();
    }

    let outcome = make_outcome(
        "check", "proj", OutcomeType::Success,
        vec![
            ("glob", ToolResultType::Success),
            ("file_write", ToolResultType::Success),
        ],
    );
    let rules = engine.analyze_and_evolve(&outcome).unwrap();
    let ordering = rules.iter()
        .filter(|r| r.source == RuleSource::OrderingPattern && r.name.contains("glob"))
        .count();
    assert_eq!(ordering, 0, "Should not generate ordering rule at ~43% success rate");
}
```

The test helper `make_outcome` constructs `SessionOutcome` with controlled tool call sequences. We use `with_min_sessions(store, 1)` to bypass the minimum session count gate so we can focus on testing the success rate threshold specifically.

GBNF grammars constrain token-by-token generation, so this is used as a retry mechanism when the model should produce a tool call but generated malformed output. The critical security concern is tool name injection into the grammar.

```rust
pub fn build_tool_call_grammar(tool_names: &[&str]) -> Result<String, String> {
    // P0 SECURITY: Validate tool names before interpolating into GBNF.
    // A malicious name containing quotes or pipes could inject arbitrary rules.
    let valid_name_re = regex::Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();

    let valid_names: Vec<&str> = tool_names.iter()
        .filter(|name| {
            if valid_name_re.is_match(name) {
                true
            } else {
                eprintln!("[SECURITY] Skipping invalid tool name for GBNF: {:?}", name);
                false
            }
        })
        .copied()
        .collect();

    if valid_names.is_empty() {
        return Err("No valid tool names remain after sanitization".to_string());
    }

    let tool_name_rule = valid_names.iter()
        .map(|name| format!("\"{}\"", name))
        .collect::<Vec<_>>()
        .join(" | ");

    Ok(format!(r#"root        ::= ws tool-call ws
tool-call   ::= "<tool_call>" ws function ws "</tool_call>"
function    ::= "<function=" tool-name ">" ws params ws "</function>"
tool-name   ::= {tool_name_rule}
params      ::= param (ws param)*
param       ::= "<parameter=" param-name ">" param-value "</parameter>"
param-name  ::= [a-zA-Z_] [a-zA-Z0-9_]*
param-value ::= [^<]*
ws          ::= [ \t\n\r]*
"#))
}
```

The injection vector: a tool name like `" | ws | "` would add whitespace as a valid tool name alternative, allowing the model to generate arbitrary text where a tool name should be. The regex `^[a-zA-Z0-9_]+$` blocks this completely. Invalid names are silently filtered (not errored) so a single bad plugin doesn't break tool calling for all tools.

The test suite should cover structural correctness, security edge cases, and the alternation logic:

```rust
#[test]
fn test_single_tool() {
    let grammar = build_tool_call_grammar(&["bash"]).unwrap();
    assert!(grammar.contains("\"bash\""));
    assert!(grammar.contains("root"));
    assert!(grammar.contains("<tool_call>"));
}

#[test]
fn test_multiple_tools_use_alternation() {
    let grammar = build_tool_call_grammar(&["bash", "file_read", "grep"]).unwrap();
    assert!(grammar.contains(" | "));
    assert!(grammar.contains("\"bash\""));
    assert!(grammar.contains("\"file_read\""));
}

#[test]
fn test_empty_tool_names_returns_error() {
    assert!(build_tool_call_grammar(&[]).is_err());
}

#[test]
fn test_invalid_tool_names_skipped() {
    let grammar = build_tool_call_grammar(&["bash", "file\"_inject", "valid_tool"]).unwrap();
    assert!(grammar.contains("\"bash\""));
    assert!(grammar.contains("\"valid_tool\""));
    assert!(!grammar.contains("file\"_inject"));
}

#[test]
fn test_all_invalid_names_returns_error() {
    let result = build_tool_call_grammar(&["file\"_inject", "a\nb", "\" | ws | \""]);
    assert!(result.is_err());
}

#[test]
fn test_param_value_allows_any_non_angle() {
    let grammar = build_tool_call_grammar(&["bash"]).unwrap();
    assert!(grammar.contains("[^<]*"));
}
```

The `[^<]*` rule for param-value is deliberately permissive: parameter values can contain any character except `<`, which prevents injection of nested XML tags. The `param-name` rule is stricter (`[a-zA-Z_][a-zA-Z0-9_]*`) because parameter names map to struct fields.

Tasks are stored as individual JSON files at `<project>/.ftai/tasks/task_<id>.json`. This gives you atomic file operations per task, easy debugging (just `cat` a file), and no database dependency.

```rust
use anyhow::Result;
use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::path::{Path, PathBuf};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TaskData {
    pub id: u64,
    pub subject: String,
    pub description: String,
    pub status: String,
    #[serde(rename = "blockedBy", default)]
    pub blocked_by: Vec<u64>,
    #[serde(default)]
    pub owner: String,
}

const VALID_STATUSES: &[&str] = &["pending", "in_progress", "completed"];

pub struct TaskTool;

impl Tool for TaskTool {
    fn name(&self) -> &str { "task" }

    fn execute(&self, params: Value, ctx: &ToolContext)
        -> Pin<Box<dyn Future<Output = Result<ToolResult>> + Send + '_>> {
        let project_path = ctx.project_path.clone();
        Box::pin(async move {
            match params["action"].as_str().unwrap_or("") {
                "create" => handle_create(&params, &project_path),
                "update" => handle_update(&params, &project_path),
                "list" => handle_list(&project_path),
                "delete" => handle_delete(&params, &project_path),
                "claim" => handle_claim(&params, &project_path),
                "" => Ok(ToolResult::error("Missing required parameter: action")),
                other => Ok(ToolResult::error(format!("Unknown action: {other}"))),
            }
        })
    }
}
```

The dependency graph is the interesting part. When a task completes, it clears itself from all other tasks' `blockedBy` lists:

```rust
fn clear_completed_dependency(project_path: &Path, completed_id: u64) {
    let dir = tasks_dir(project_path);
    if !dir.exists() { return; }
    for entry in std::fs::read_dir(&dir).ok().into_iter().flatten().flatten() {
        let path = entry.path();
        if !path.extension().map_or(false, |e| e == "json") { continue; }
        if let Ok(content) = std::fs::read_to_string(&path) {
            if let Ok(mut task) = serde_json::from_str::<TaskData>(&content) {
                if task.blocked_by.contains(&completed_id) {
                    task.blocked_by.retain(|&id| id != completed_id);
                    let json = serde_json::to_string_pretty(&task).unwrap_or_default();
                    let _ = std::fs::write(&path, json);
                }
            }
        }
    }
}
```

The claim mechanism uses an atomic check-and-set pattern: only claim if `owner` is empty. This prevents race conditions in multi-agent scenarios.

```rust
fn handle_claim(params: &Value, project_path: &Path) -> Result<ToolResult> {
    let id = params["id"].as_u64().ok_or("Missing id")?;
    let owner = params["owner"].as_str().unwrap_or("agent");
    let mut task = read_task(project_path, id)?;
    if !task.owner.is_empty() {
        return Ok(ToolResult::error(format!("Task #{id} already claimed by '{}'", task.owner)));
    }
    task.owner = owner.to_string();
    write_task(project_path, &task)?;
    Ok(ToolResult::success(format!("Claimed task #{id} for '{owner}'")))
}
```

Every field that flows into filenames, JSON storage, or display needs validation:

```rust
fn validate_id(id: u64) -> Result<(), String> {
    if id == 0 {
        return Err("Task ID must be greater than 0.".to_string());
    }
    if id > 999_999 {
        return Err("Task ID exceeds maximum (999999).".to_string());
    }
    Ok(())
}

fn validate_text_field(value: &str, field_name: &str, max_len: usize) -> Result<(), String> {
    if value.is_empty() {
        return Err(format!("{field_name} must not be empty."));
    }
    if value.len() > max_len {
        return Err(format!("{field_name} too long ({} chars, max {max_len}).", value.len()));
    }
    if value.contains('\0') {
        return Err(format!("{field_name} must not contain null bytes."));
    }
    Ok(())
}
```

